const repos = $input.item.json.items || [];
const crypto = require('crypto');
const now = Date.now();

return repos
  .map(repo => {
    const createdAt = new Date(repo.created_at);
    const daysOld = Math.max(1, (now - createdAt.getTime()) / (1000 * 60 * 60 * 24));
    const velocity = repo.stargazers_count / daysOld;
    const title = `${repo.full_name}: ${repo.description || 'No description'}`;
    const content_hash = crypto.createHash('sha256')
      .update(`${repo.full_name.toLowerCase()}|github`)
      .digest('hex');

    return {
      json: {
        source: 'github',
        source_category: 'open_source',
        title: title,
        url: repo.html_url,
        raw_content: repo.description || '',
        entities: [],
        metadata: {
          full_name: repo.full_name,
          stars: repo.stargazers_count,
          forks: repo.forks_count,
          language: repo.language,
          topics: repo.topics || [],
          velocity: Math.round(velocity * 100) / 100,
          created_at: repo.created_at,
          updated_at: repo.updated_at
        },
        collected_at: new Date().toISOString(),
        content_hash: content_hash
      }
    };
  })
  .filter(r => r.json.metadata.velocity > 10 || r.json.metadata.stars > 100);
